package store

import (
	"context"
	"os"
	"testing"
	"time"

	"github.com/alicebob/miniredis/v2"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

func setupRedisTest(t *testing.T) (*miniredis.Miniredis, *RedisStore, context.Context) {
	t.Helper()

	mr, err := miniredis.Run()
	if err != nil {
		t.Fatalf("Failed to start miniredis: %v", err)
	}

	os.Setenv("REDIS_ADDR", mr.Addr())
	os.Setenv("REDIS_PASSWORD_REQUIRED", "false")

	store, err := newRedisStore()
	if err != nil {
		mr.Close()
		t.Fatalf("Failed to create Redis store: %v", err)
	}

	return mr, store, context.Background()
}

func TestRedisStorePing(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	err := store.Ping(ctx)
	if err != nil {
		t.Errorf("Ping failed: %v", err)
	}
}

func TestRedisStoreGetSandboxBySessionIDNotFound(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	_, err := store.GetSandboxBySessionID(ctx, "nonexistent")
	if err != ErrNotFound {
		t.Errorf("Expected ErrNotFound, got: %v", err)
	}
}

func TestRedisStoreStoreAndGetSandbox(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID: "test-session",
		SandboxID: "test-sandbox",
		Name:      "test-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now,
	}

	err := store.StoreSandbox(ctx, sandbox)
	if err != nil {
		t.Fatalf("StoreSandbox failed: %v", err)
	}

	retrieved, err := store.GetSandboxBySessionID(ctx, "test-session")
	if err != nil {
		t.Fatalf("GetSandboxBySessionID failed: %v", err)
	}

	if retrieved.SessionID != sandbox.SessionID {
		t.Errorf("SessionID mismatch: got %s, want %s", retrieved.SessionID, sandbox.SessionID)
	}
	if retrieved.SandboxID != sandbox.SandboxID {
		t.Errorf("SandboxID mismatch: got %s, want %s", retrieved.SandboxID, sandbox.SandboxID)
	}
}

func TestRedisStoreStoreSandboxNil(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	err := store.StoreSandbox(ctx, nil)
	if err == nil {
		t.Error("Expected error for nil sandbox")
	}
}

