		ExpiresAt: time.Time{},
	}

	err := store.StoreSandbox(ctx, sandbox)
	if err == nil {
		t.Error("Expected error for zero ExpiresAt")
	}
}

func TestRedisStoreStoreSandboxDuplicate(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID: "test-session",
		SandboxID: "test-sandbox",
		Name:      "test-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now,
	}

	err := store.StoreSandbox(ctx, sandbox)
	if err != nil {
		t.Fatalf("First StoreSandbox failed: %v", err)
	}

	err = store.StoreSandbox(ctx, sandbox)
	if err == nil {
		t.Error("Expected error for duplicate session")
	}
}

func TestRedisStoreUpdateSandbox(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID: "test-session",
		SandboxID: "test-sandbox",
		Name:      "test-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now,
	}

	err := store.StoreSandbox(ctx, sandbox)
	if err != nil {
		t.Fatalf("StoreSandbox failed: %v", err)
	}

	sandbox.Name = "updated-name"
	err = store.UpdateSandbox(ctx, sandbox)
	if err != nil {
		t.Fatalf("UpdateSandbox failed: %v", err)
	}

	retrieved, err := store.GetSandboxBySessionID(ctx, "test-session")
	if err != nil {
		t.Fatalf("GetSandboxBySessionID failed: %v", err)
	}

	if retrieved.Name != "updated-name" {
		t.Errorf("Name not updated: got %s, want updated-name", retrieved.Name)
	}
}

