	err := store.StoreSandbox(ctx, sandbox)
	if err != nil {
		t.Fatalf("StoreSandbox failed: %v", err)
	}

	err = store.DeleteSandboxBySessionID(ctx, "test-session")
	if err != nil {
		t.Fatalf("DeleteSandboxBySessionID failed: %v", err)
	}

	_, err = store.GetSandboxBySessionID(ctx, "test-session")
	if err != ErrNotFound {
		t.Errorf("Expected ErrNotFound after delete, got: %v", err)
	}
