func TestRedisStoreListExpiredSandboxes(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()

	expiredSandbox := &types.SandboxInfo{
		SessionID: "expired-session",
		SandboxID: "expired-sandbox",
		Name:      "expired-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(-time.Hour),
		CreatedAt: now.Add(-2 * time.Hour),
	}

	activeSandbox := &types.SandboxInfo{
		SessionID: "active-session",
		SandboxID: "active-sandbox",
		Name:      "active-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now,
	}

	err := store.StoreSandbox(ctx, expiredSandbox)
	if err != nil {
		t.Fatalf("StoreSandbox expired failed: %v", err)
	}

	err = store.StoreSandbox(ctx, activeSandbox)
	if err != nil {
		t.Fatalf("StoreSandbox active failed: %v", err)
	}

	expired, err := store.ListExpiredSandboxes(ctx, now, 10)
	if err != nil {
		t.Fatalf("ListExpiredSandboxes failed: %v", err)
	}

	if len(expired) != 1 {
		t.Errorf("Expected 1 expired sandbox, got %d", len(expired))
	} else if expired[0].SessionID != "expired-session" {
		t.Errorf("Expected expired-session, got %s", expired[0].SessionID)
	}
}

