func TestRedisStoreUpdateSessionLastActivity(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID: "test-session",
